#include<cstdio>
#include<vector>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
typedef long long LL;
vector<int> construct_permutation(LL k)
{
	vector<bool> K;
	while(k)K.push_back(k&1),k>>=1;
	vector<int> a;int n=K.size();
//	printf("qwq :::::: ",n);
	for(int i=0;i<(n-1);++i)a.push_back(i);
	int cur=n-2,f1=-1,f2=-1;
	for(int i=n-2;i>=0;--i)if(K[i])
	{
		if(i>0&&K[i-1]&&~f1&&~f2)
		{
			vector<int> tmp;
			for(int &v:a)if(v==f1||v==f2)++v;--i;++cur;
			for(int j=0;j<i;++j)tmp.push_back(a[j]);tmp.push_back(f1);
			for(unsigned j=i;j<a.size();++j)tmp.push_back(a[j]);
			a=tmp;++f1;++f2;
		}
		else
		{
			vector<int> tmp;
			for(int j=0;j<i;++j)tmp.push_back(a[j]);
			tmp.push_back(++cur);
			for(unsigned j=i;j<a.size();++j)tmp.push_back(a[j]);
			a=tmp;if(cur>f2)f1=f2,f2=cur;else if(cur>f1)f1=cur;
		}
		
	}
	return a;
}
